@page "/dispatcher"
@rendermode InteractiveAuto
@attribute [Microsoft.AspNetCore.Authorization.Authorize(Roles = "Dispatcher")]
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@inject IShipmentService ShipmentService

<PageTitle>Dispatcher Dashboard</PageTitle>

<h1>Dispatcher Dashboard</h1>

<div class="mb-3 row align-items-end">
    <div class="col-auto">
        <label class="form-label">Filter by Status</label>
        <select class="form-select" @bind="statusFilter">
            <option value="">All</option>
            @foreach (var s in Enum.GetValues<ShipmentStatus>())
            {
                <option value="@s">@s</option>
            }
        </select>
    </div>
    <div class="col-auto">
        <label class="form-label">Search Destination</label>
        <input type="text" class="form-control" placeholder="Type to filter…" @bind="destinationFilter" @bind:event="oninput" />
    </div>
    <div class="col-auto">
        <button class="btn btn-outline-primary" @onclick="LoadShipments">
            Refresh
        </button>
    </div>
</div>

@if (shipments is null)
{
    <p><em>Loading shipments…</em></p>
}
else if (!FilteredShipments.Any())
{
    <div class="alert alert-info">No shipments match the current filters.</div>
}
else
{
    <table class="table table-striped table-hover">
        <thead class="table-dark">
            <tr>
                <th>Tracking #</th>
                <th>Origin</th>
                <th>Destination</th>
                <th>Recipient</th>
                <th>Weight (kg)</th>
                <th>Shipped</th>
                <th>Est. Delivery</th>
                <th>Status</th>
                <th>Action</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var s in FilteredShipments)
            {
                <tr>
                    <td><code>@s.TrackingNumber</code></td>
                    <td>@s.Origin</td>
                    <td>@s.Destination</td>
                    <td>@s.RecipientName</td>
                    <td>@s.WeightKg.ToString("F1")</td>
                    <td>@s.ShippedDate.ToString("yyyy-MM-dd")</td>
                    <td>@s.EstimatedDelivery.ToString("yyyy-MM-dd")</td>
                    <td>
                        <span class="badge @StatusBadgeClass(s.Status)">@s.Status</span>
                    </td>
                    <td>
                        @if (s.Status != ShipmentStatus.Delivered && s.Status != ShipmentStatus.Returned)
                        {
                            <div class="input-group input-group-sm" style="min-width: 200px;">
                                <select class="form-select form-select-sm" @bind="selectedStatuses[s.Id]">
                                    @foreach (var ns in Enum.GetValues<ShipmentStatus>())
                                    {
                                        <option value="@ns">@ns</option>
                                    }
                                </select>
                                <button class="btn btn-sm btn-warning" @onclick="() => UpdateStatus(s)"
                                        disabled="@updatingIds.Contains(s.Id)">
                                    @(updatingIds.Contains(s.Id) ? "…" : "Update")
                                </button>
                            </div>
                        }
                        else
                        {
                            <span class="text-muted">—</span>
                        }
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@if (!string.IsNullOrEmpty(errorMessage))
{
    <div class="alert alert-danger mt-2">@errorMessage</div>
}

@code {
    private List<ShipmentDto>? shipments;
    private string statusFilter = "";
    private string destinationFilter = "";
    private string? errorMessage;
    private Dictionary<int, ShipmentStatus> selectedStatuses = new();
    private HashSet<int> updatingIds = new();

    private IEnumerable<ShipmentDto> FilteredShipments =>
        (shipments ?? [])
            .Where(s => string.IsNullOrEmpty(statusFilter) || s.Status.ToString() == statusFilter)
            .Where(s => string.IsNullOrEmpty(destinationFilter) ||
                        s.Destination.Contains(destinationFilter, StringComparison.OrdinalIgnoreCase));

    protected override async Task OnInitializedAsync() => await LoadShipments();

    private async Task LoadShipments()
    {
        errorMessage = null;
        try
        {
            shipments = await ShipmentService.GetAllShipmentsAsync();
            selectedStatuses = shipments.ToDictionary(s => s.Id, s => s.Status);
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load shipments: {ex.Message}";
        }
    }

    private async Task UpdateStatus(ShipmentDto shipment)
    {
        errorMessage = null;
        updatingIds.Add(shipment.Id);
        try
        {
            var newStatus = selectedStatuses[shipment.Id];
            var updated = await ShipmentService.UpdateStatusAsync(shipment.Id, newStatus);
            if (updated is not null)
            {
                shipment.Status = updated.Status;
                shipment.ActualDelivery = updated.ActualDelivery;
            }
            else
            {
                errorMessage = $"Failed to update shipment {shipment.TrackingNumber}.";
            }
        }
        catch (Exception ex)
        {
            errorMessage = $"Error updating status: {ex.Message}";
        }
        finally
        {
            updatingIds.Remove(shipment.Id);
        }
    }

    private static string StatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info text-dark",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Returned => "bg-danger",
        _ => "bg-secondary"
    };
}

@page "/track"
@rendermode InteractiveAuto
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@inject IShipmentService ShipmentService

<PageTitle>Track Shipment</PageTitle>

<h1>Track Your Shipment</h1>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input type="text" class="form-control" placeholder="Enter tracking number (e.g. SHP-001)"
                   @bind="trackingNumber" @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="Search" disabled="@isSearching">
                @(isSearching ? "Searching…" : "Track")
            </button>
        </div>
    </div>
</div>

@if (searched && shipment is null)
{
    <div class="alert alert-warning">
        No shipment found for tracking number <strong>@searchedNumber</strong>.
        Please verify and try again.
    </div>
}

@if (shipment is not null)
{
    <div class="card">
        <div class="card-header d-flex justify-content-between align-items-center">
            <h5 class="mb-0">Shipment <code>@shipment.TrackingNumber</code></h5>
            <span class="badge @StatusBadgeClass(shipment.Status) fs-6">@shipment.Status</span>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <dl>
                        <dt>Recipient</dt>
                        <dd>@shipment.RecipientName</dd>
                        <dt>Origin</dt>
                        <dd>@shipment.Origin</dd>
                        <dt>Destination</dt>
                        <dd>@shipment.Destination</dd>
                        <dt>Weight</dt>
                        <dd>@shipment.WeightKg.ToString("F1") kg</dd>
                    </dl>
                </div>
                <div class="col-md-6">
                    <dl>
                        <dt>Shipped Date</dt>
                        <dd>@shipment.ShippedDate.ToString("MMMM d, yyyy")</dd>
                        <dt>Estimated Delivery</dt>
                        <dd class="fw-bold text-primary">@shipment.EstimatedDelivery.ToString("MMMM d, yyyy")</dd>
                        @if (shipment.ActualDelivery.HasValue)
                        {
                            <dt>Actual Delivery</dt>
                            <dd class="text-success fw-bold">@shipment.ActualDelivery.Value.ToString("MMMM d, yyyy")</dd>
                        }
                    </dl>
                </div>
            </div>

            <!-- Progress tracker -->
            <h6 class="mt-3">Shipment Progress</h6>
            <div class="progress" style="height: 30px;">
                <div class="progress-bar @ProgressBarClass(shipment.Status)" role="progressbar"
                     style="width: @ProgressPercent(shipment.Status)%"
                     aria-valuenow="@ProgressPercent(shipment.Status)" aria-valuemin="0" aria-valuemax="100">
                    @shipment.Status
                </div>
            </div>
            <div class="d-flex justify-content-between mt-1 small text-muted">
                <span>Pending</span>
                <span>Picked Up</span>
                <span>In Transit</span>
                <span>Out for Delivery</span>
                <span>Delivered</span>
            </div>
        </div>
    </div>
}

@code {
    private string trackingNumber = "";
    private string searchedNumber = "";
    private ShipmentDto? shipment;
    private bool searched;
    private bool isSearching;

    private async Task HandleKeyDown(Microsoft.AspNetCore.Components.Web.KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await Search();
    }

    private async Task Search()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;
        isSearching = true;
        searched = true;
        searchedNumber = trackingNumber.Trim();
        try
        {
            shipment = await ShipmentService.GetByTrackingNumberAsync(searchedNumber);
        }
        catch
        {
            shipment = null;
        }
        finally
        {
            isSearching = false;
        }
    }

    private static string StatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info text-dark",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Returned => "bg-danger",
        _ => "bg-secondary"
    };

    private static string ProgressBarClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Returned => "bg-danger",
        ShipmentStatus.Delivered => "bg-success",
        _ => "bg-primary progress-bar-striped progress-bar-animated"
    };

    private static int ProgressPercent(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => 10,
        ShipmentStatus.PickedUp => 30,
        ShipmentStatus.InTransit => 55,
        ShipmentStatus.OutForDelivery => 80,
        ShipmentStatus.Delivered => 100,
        ShipmentStatus.Returned => 100,
        _ => 0
    };
}

