                                        disabled="@updatingIds.Contains(s.Id)">
                                    @(updatingIds.Contains(s.Id) ? "…" : "Update")
                                </button>
                            </div>
                        }
                        else
                        {
                            <span class="text-muted">—</span>
                        }
