                    RecipientName = "Diana Chen",
                    WeightKg = 1.8
                },
                new Shipment
                {
                    TrackingNumber = "SHP-006",
                    Origin = "Paris, France",
                    Destination = "Lagos, Nigeria",
                    Status = ShipmentStatus.InTransit,
                    ShippedDate = now.AddDays(-2),
                    EstimatedDelivery = now.AddDays(5),
                    RecipientName = "Emmanuel Okafor",
                    WeightKg = 15.0
                }
            );
            await db.SaveChangesAsync();
        }
    }

    private static async Task EnsureUser(UserManager<ApplicationUser> userManager,
        string email, string password, string role)
    {
        if (await userManager.FindByEmailAsync(email) is not null) return;

        var user = new ApplicationUser
        {
            UserName = email,
            Email = email,
            EmailConfirmed = true
        };
        var result = await userManager.CreateAsync(user, password);
        if (result.Succeeded)
            await userManager.AddToRoleAsync(user, role);
    }
}

using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Data;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentApi(this WebApplication app)
    {
        var group = app.MapGroup("api/shipments");

        group.MapGet("/", [Authorize(Roles = "Dispatcher")] async (ApplicationDbContext db) =>
        {
            var shipments = await db.Shipments
                .OrderByDescending(s => s.ShippedDate)
                .Select(s => s.ToDto())
                .ToListAsync();
            return Results.Ok(shipments);
        });

        // Public tracking endpoint — any authenticated user can look up by tracking number
        group.MapGet("/track/{trackingNumber}", [Authorize] async (string trackingNumber, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments
                .FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
            return shipment is null ? Results.NotFound() : Results.Ok(shipment.ToDto());
        });

        group.MapPut("/{id:int}/status", [Authorize(Roles = "Dispatcher")] async (
            int id, [FromBody] StatusUpdateRequest request, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments.FindAsync(id);
            if (shipment is null)
                return Results.NotFound();

            shipment.Status = request.Status;
            if (request.Status == ShipmentStatus.Delivered)
                shipment.ActualDelivery = DateTime.UtcNow;

            await db.SaveChangesAsync();
            return Results.Ok(shipment.ToDto());
        });
    }

    public record StatusUpdateRequest(ShipmentStatus Status);
}

